1	package com.eaglepoint.storehub.service;
2	
3	import com.eaglepoint.storehub.annotation.Audited;
4	import com.eaglepoint.storehub.annotation.DataScope;
5	import com.eaglepoint.storehub.aspect.DataScopeContext;
6	import com.eaglepoint.storehub.dto.CheckInRequest;
7	import com.eaglepoint.storehub.dto.CheckInResponse;
8	import com.eaglepoint.storehub.entity.*;
9	import com.eaglepoint.storehub.enums.CheckInStatus;
10	import com.eaglepoint.storehub.repository.*;
11	import com.eaglepoint.storehub.service.SiteAuthorizationService;
12	import lombok.RequiredArgsConstructor;
13	import lombok.extern.slf4j.Slf4j;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import jakarta.servlet.http.HttpServletRequest;
18	import org.springframework.web.context.request.RequestContextHolder;
19	import org.springframework.web.context.request.ServletRequestAttributes;
20	
21	import java.nio.charset.StandardCharsets;
22	import java.security.MessageDigest;
23	import java.time.*;
24	import java.util.HexFormat;
25	import java.util.List;
26	import java.util.Optional;
27	
28	@Slf4j
29	@Service
30	@RequiredArgsConstructor
31	public class CheckInService {
32	
33	    private static final Duration EARLY_WINDOW = Duration.ofMinutes(15);
34	    private static final Duration LATE_WINDOW = Duration.ofMinutes(10);
35	    private static final int FRAUD_ATTEMPT_THRESHOLD = 5;
36	    private static final Duration FRAUD_WINDOW = Duration.ofMinutes(10);
37	    private static final Duration DUPLICATE_WINDOW = Duration.ofMinutes(60);
38	
39	    private final CheckInRepository checkInRepository;
40	    private final FraudAlertRepository fraudAlertRepository;
41	    private final UserRepository userRepository;
42	    private final OrganizationRepository organizationRepository;
43	    private final ShiftAssignmentRepository shiftAssignmentRepository;
44	    private final DeviceBindingRepository deviceBindingRepository;
45	    private final SiteAuthorizationService siteAuth;
46	
47	    @Audited(action = "CHECK_IN", entityType = "CheckIn")
48	    @Transactional
49	    public CheckInResponse checkIn(Long userId, CheckInRequest request) {
50	        User user = userRepository.findById(userId)
51	                .orElseThrow(() -> new IllegalArgumentException("User not found"));
52	        Organization site = organizationRepository.findById(request.getSiteId())
53	                .orElseThrow(() -> new IllegalArgumentException("Site not found"));
54	
55	        siteAuth.requireSiteAccess(request.getSiteId());
56	
57	        // Team scope enforcement: if user has a team, verify it belongs to the site
58	        if (user.getTeam() != null && user.getSite() != null
59	                && !user.getSite().getId().equals(request.getSiteId())) {
60	            throw new com.eaglepoint.storehub.config.AccessDeniedException(
61	                    "Check-in denied: user's team is not assigned to this site");
62	        }
63	
64	        Instant now = Instant.now();
65	
66	        // Device fingerprint augmentation (computed early for use in flagged records)
67	        String normalizedFingerprint = augmentFingerprint(request.getDeviceFingerprint());
68	
69	        // Server-derived schedule — never trust client scheduledTime
70	        LocalDate today = LocalDate.now();
71	        Optional<ShiftAssignment> shiftOpt = shiftAssignmentRepository.findActiveShift(userId, request.getSiteId(), today);
72	
73	        Instant scheduled;
74	        if (shiftOpt.isPresent()) {
75	            ShiftAssignment shift = shiftOpt.get();
76	            scheduled = shift.getShiftStart().atDate(today).atZone(ZoneId.systemDefault()).toInstant();
77	        } else {
78	            // No shift assigned — persist flagged record and reject check-in
79	            CheckIn flagged = checkInRepository.save(CheckIn.builder()
80	                    .user(user).site(site).timestamp(now).scheduledTime(now)
81	                    .deviceFingerprint(normalizedFingerprint)
82	                    .locationDescription(request.getLocationDescription())
83	                    .status(CheckInStatus.FLAGGED).build());
84	            fraudAlertRepository.save(FraudAlert.builder()
85	                    .user(user).reason("NO_ACTIVE_SHIFT")
86	                    .details("Check-in attempted with no active shift assignment for " + java.time.LocalDate.now())
87	                    .build());
88	            log.warn("Check-in rejected: no active shift for userId={}, siteId={}", userId, request.getSiteId());
89	            return buildResponse(flagged.getId(), userId, request.getSiteId(), now, now,
90	                    CheckInStatus.FLAGGED, "No active shift assignment found for today",
91	                    request.getLocationDescription(), normalizedFingerprint);
92	        }
93	
94	        // Fraud detection: >5 attempts in 10 minutes
95	        long recentAttempts = checkInRepository.countByUserIdSince(userId, now.minus(FRAUD_WINDOW));
96	        if (recentAttempts >= FRAUD_ATTEMPT_THRESHOLD) {
97	            fraudAlertRepository.save(FraudAlert.builder()
98	                    .user(user)
99	                    .reason("EXCESSIVE_CHECKIN_ATTEMPTS")
100	                    .details("User attempted " + (recentAttempts + 1) + " check-ins within 10 minutes")
101	                    .build());
102	
103	            log.warn("Fraud detection: excessive check-in attempts ({}) by userId={} within 10 minutes", recentAttempts + 1, userId);
104	            // Persist flagged check-in with raw evidence for supervisor review
105	            CheckIn flagged = checkInRepository.save(CheckIn.builder()
106	                    .user(user).site(site).timestamp(now).scheduledTime(scheduled)
107	                    .deviceFingerprint(normalizedFingerprint)
108	                    .locationDescription(request.getLocationDescription())
109	                    .status(CheckInStatus.FLAGGED).build());
110	            return buildResponse(flagged.getId(), userId, request.getSiteId(), now, scheduled,
111	                    CheckInStatus.FLAGGED, "Too many check-in attempts. Your account has been flagged.");
112	        }
113	
114	        // Duplicate check-in blocking: device-scoped — no valid check-in from same device within 60 minutes
115	        long recentValid = (normalizedFingerprint != null)
116	                ? checkInRepository.countValidCheckInsByDevice(userId, request.getSiteId(), normalizedFingerprint, now.minus(DUPLICATE_WINDOW))
117	                : checkInRepository.countValidCheckInsSince(userId, request.getSiteId(), now.minus(DUPLICATE_WINDOW));
118	        if (recentValid > 0) {
119	            log.warn("Duplicate check-in blocked for userId={} at siteId={}", userId, request.getSiteId());
120	            CheckIn flagged = checkInRepository.save(CheckIn.builder()
121	                    .user(user).site(site).timestamp(now).scheduledTime(scheduled)
122	                    .deviceFingerprint(normalizedFingerprint)
123	                    .locationDescription(request.getLocationDescription())
124	                    .status(CheckInStatus.FLAGGED).build());
125	            // Create linked fraud alert requiring supervisor resolution
126	            fraudAlertRepository.save(FraudAlert.builder()
127	                    .user(user).reason("DUPLICATE_CHECKIN")
128	                    .details("Duplicate check-in within 60 minutes at site " + request.getSiteId())
129	                    .build());
130	            return buildResponse(flagged.getId(), userId, request.getSiteId(), now, scheduled,
131	                    CheckInStatus.FLAGGED, "Duplicate check-in blocked. A valid check-in exists within the last 60 minutes.");
132	        }
133	
134	        // Device binding check
135	        if (normalizedFingerprint != null) {
136	            List<DeviceBinding> bindings = deviceBindingRepository.findByUserIdAndActiveTrue(userId);
137	            if (bindings.isEmpty()) {
138	                // First device — auto-bind
139	                deviceBindingRepository.save(DeviceBinding.builder()
140	                        .user(user).deviceHash(normalizedFingerprint).deviceLabel("Auto-bound").build());
141	            } else {
142	                boolean knownDevice = bindings.stream().anyMatch(b -> b.getDeviceHash().equals(normalizedFingerprint));
143	                if (!knownDevice) {
144	                    log.warn("Device mismatch: userId={}, bound devices={}", userId, bindings.size());
145	                    fraudAlertRepository.save(FraudAlert.builder()
146	                            .user(user).reason("DEVICE_MISMATCH")
147	                            .details("Unrecognized device hash: " + normalizedFingerprint.substring(0, 12) + "...").build());
148	                }
149	            }
150	        }
151	
152	        // Window validation: 15m before to 10m after server-derived scheduled time
153	        CheckInStatus status;
154	        String message;
155	        Instant windowStart = scheduled.minus(EARLY_WINDOW);
156	        Instant windowEnd = scheduled.plus(LATE_WINDOW);
157	
158	        if (now.isBefore(windowStart)) {
159	            status = CheckInStatus.FLAGGED;
160	            message = "Check-in rejected: outside allowed window (too early).";
161	        } else if (now.isAfter(windowEnd)) {
162	            status = CheckInStatus.FLAGGED;
163	            message = "Check-in rejected: outside allowed window (too late).";
164	        } else {
165	            status = CheckInStatus.VALID;
166	            message = "Check-in successful.";
167	        }
168	
169	        CheckIn checkIn = CheckIn.builder()
170	                .user(user)
171	                .site(site)
172	                .timestamp(now)
173	                .scheduledTime(scheduled)
174	                .deviceFingerprint(normalizedFingerprint)
175	                .locationDescription(request.getLocationDescription())
176	                .status(status)
177	                .build();
178	
179	        checkIn = checkInRepository.save(checkIn);
180	
181	        if (status == CheckInStatus.VALID) {
182	            log.info("Valid check-in recorded: userId={}, siteId={}, checkInId={}", userId, request.getSiteId(), checkIn.getId());
183	        } else if (status == CheckInStatus.FLAGGED) {
184	            // Create linked fraud alert for out-of-window flagged check-ins
185	            fraudAlertRepository.save(FraudAlert.builder()
186	                    .user(user).reason("OUT_OF_WINDOW")
187	                    .details("Check-in outside allowed window: " + message)
188	                    .build());
189	        }
190	
191	        return buildResponse(checkIn.getId(), userId, request.getSiteId(), now, scheduled, status, message,
192	                request.getLocationDescription(), normalizedFingerprint);
193	    }
194	
195	    @DataScope(requireDevice = true)
196	    @Transactional(readOnly = true)
197	    public List<CheckInResponse> getCheckInsBySite(Long siteId, Instant start, Instant end) {
198	        List<Long> visibleSites = DataScopeContext.get();
199	        if (visibleSites != null && !visibleSites.contains(siteId)) {
200	            throw new com.eaglepoint.storehub.config.AccessDeniedException("Access denied: site not in your data scope");
201	        }
202	
203	        List<CheckIn> results = checkInRepository.findBySiteAndTimeRange(siteId, start, end);
204	
205	        // Device scope filtering: when device context is set, only return check-ins from that device
206	        String deviceHash = DataScopeContext.getDeviceHash();
207	        if (deviceHash != null) {
208	            results = results.stream()
209	                    .filter(c -> deviceHash.equals(c.getDeviceFingerprint()))
210	                    .toList();
211	        }
212	
213	        // Work-order scope filtering: when work-order context is set, only return check-ins
214	        // from users with matching shift assignments (work-order = shift)
215	        Long workOrderId = DataScopeContext.getWorkOrderId();
216	        if (workOrderId != null) {
217	            results = results.stream()
218	                    .filter(c -> {
219	                        var shift = shiftAssignmentRepository.findActiveShift(
220	                                c.getUser().getId(), siteId, LocalDate.now());
221	                        return shift.isPresent() && shift.get().getId().equals(workOrderId);
222	                    })
223	                    .toList();
224	        }
225	
226	        return results.stream()
227	                .map(c -> buildResponse(c.getId(), c.getUser().getId(), c.getSite().getId(),
228	                        c.getTimestamp(), c.getScheduledTime(), c.getStatus(), null))
229	                .toList();
230	    }
231	
232	    /**
233	     * Augments client-provided fingerprint with server-side data (IP + User-Agent hash)
234	     * to make it harder to forge.
235	     */
236	    private String augmentFingerprint(String clientFingerprint) {
237	        try {
238	            ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
239	            String serverPart = "";
240	            if (attrs != null) {
241	                HttpServletRequest req = attrs.getRequest();
242	                String ip = req.getRemoteAddr();
243	                String ua = req.getHeader("User-Agent");
244	                serverPart = ip + "|" + (ua != null ? ua : "");
245	            }
246	            String combined = (clientFingerprint != null ? clientFingerprint : "") + "|" + serverPart;
247	            MessageDigest md = MessageDigest.getInstance("SHA-256");
248	            byte[] hash = md.digest(combined.getBytes(StandardCharsets.UTF_8));
249	            return HexFormat.of().formatHex(hash);
250	        } catch (Exception e) {
251	            return clientFingerprint;
252	        }
253	    }
254	
255	    @Transactional(readOnly = true)
256	    public List<FraudAlert> getUnresolvedAlerts() {
257	        List<FraudAlert> allAlerts = fraudAlertRepository.findByResolvedFalseOrderByCreatedAtDesc();
258	        // Enterprise admin sees all; others see only in-scope site alerts
259	        return allAlerts.stream().filter(alert -> {
260	            Long alertSiteId = null;
261	            // Derive site from the user's site assignment
262	            if (alert.getUser() != null && alert.getUser().getSite() != null) {
263	                alertSiteId = alert.getUser().getSite().getId();
264	            }
265	            return siteAuth.canAccessSite(alertSiteId);
266	        }).toList();
267	    }
268	
269	    @Audited(action = "RESOLVE_FRAUD_ALERT", entityType = "FraudAlert")
270	    @Transactional
271	    public FraudAlert resolveFraudAlert(Long alertId, Long resolverId, String note) {
272	        String trimmedNote = note != null ? note.trim() : "";
273	        if (trimmedNote.length() < 10) {
274	            throw new IllegalArgumentException("Supervisor resolution note must be at least 10 characters");
275	        }
276	
277	        FraudAlert alert = fraudAlertRepository.findById(alertId)
278	                .orElseThrow(() -> new IllegalArgumentException("Fraud alert not found"));
279	
280	        // Enforce site-scope on resolution — manager must have access to the alert's site
281	        Long alertSiteId = (alert.getUser() != null && alert.getUser().getSite() != null)
282	                ? alert.getUser().getSite().getId() : null;
283	        siteAuth.requireSiteAccess(alertSiteId);
284	
285	        User resolver = userRepository.findById(resolverId)
286	                .orElseThrow(() -> new IllegalArgumentException("Resolver not found"));
287	
288	        alert.setResolved(true);
289	        alert.setResolverNote(trimmedNote);
290	        alert.setResolvedBy(resolver);
291	        alert.setResolvedAt(Instant.now());
292	
293	        log.info("Fraud alert resolved: alertId={}, resolverId={}", alertId, resolverId);
294	        return fraudAlertRepository.save(alert);
295	    }
296	
297	    private CheckInResponse buildResponse(Long id, Long userId, Long siteId,
298	                                           Instant timestamp, Instant scheduled,
299	                                           CheckInStatus status, String message) {
300	        return buildResponse(id, userId, siteId, timestamp, scheduled, status, message, null, null);
301	    }
302	
303	    private CheckInResponse buildResponse(Long id, Long userId, Long siteId,
304	                                           Instant timestamp, Instant scheduled,
305	                                           CheckInStatus status, String message,
306	                                           String locationDescription, String deviceHash) {
307	        // Compute timing classification independently from status
308	        // This ensures FLAGGED check-ins still show correct timing (EARLY/LATE/ON_TIME)
309	        String windowClass;
310	        if (scheduled != null && timestamp != null) {
311	            Instant windowStart = scheduled.minus(EARLY_WINDOW);
312	            Instant windowEnd = scheduled.plus(LATE_WINDOW);
313	            if (timestamp.isBefore(windowStart)) {
314	                windowClass = "EARLY";
315	            } else if (timestamp.isAfter(windowEnd)) {
316	                windowClass = "LATE";
317	            } else {
318	                windowClass = "ON_TIME";
319	            }
320	        } else {
321	            windowClass = "UNKNOWN";
322	        }
323	
324	        String maskedDevice = deviceHash != null && deviceHash.length() > 8
325	                ? deviceHash.substring(0, 8) + "..." : null;
326	
327	        return CheckInResponse.builder()
328	                .id(id).userId(userId).siteId(siteId)
329	                .timestamp(timestamp).scheduledTime(scheduled)
330	                .status(status).message(message)
331	                .locationDescription(locationDescription)
332	                .deviceEvidenceToken(maskedDevice)
333	                .windowClassification(windowClass)
334	                .flaggedForReview(status == CheckInStatus.FLAGGED)
335	                .build();
336	    }
337	}
