11	import com.eaglepoint.storehub.repository.UserRepository;
12	import lombok.RequiredArgsConstructor;
13	import lombok.extern.slf4j.Slf4j;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import java.nio.charset.StandardCharsets;
18	import java.security.MessageDigest;
19	import java.security.NoSuchAlgorithmException;
20	import java.util.List;
21	import java.util.Map;
22	import java.util.concurrent.ThreadLocalRandom;
23	
24	/**
25	 * Deterministic bucketing service that assigns users to experiment variants
26	 * using a hash of user_id + experiment_name. No external server required.
27	 */
28	@Slf4j
29	@Service
30	@RequiredArgsConstructor
31	public class ExperimentService {
32	
33	    private static final double EPSILON = 0.1;
34	
35	    private final ExperimentRepository experimentRepository;
36	    private final ExperimentOutcomeRepository outcomeRepository;
37	    private final UserRepository userRepository;
38	
39	    @Audited(action = "CREATE", entityType = "Experiment")
40	    @Transactional
41	    public ExperimentDto createExperiment(ExperimentDto dto) {
42	        if (experimentRepository.findByName(dto.getName()).isPresent()) {
43	            throw new IllegalArgumentException("Experiment name already exists");
44	        }
45	
46	        Experiment exp = Experiment.builder()
47	                .name(dto.getName())
48	                .type(dto.getType())
49	                .variantCount(dto.getVariantCount())
50	                .active(true)
51	                .description(dto.getDescription())
52	                .build();
53	
54	        return toDto(experimentRepository.save(exp));
55	    }
56	
57	    @Transactional(readOnly = true)
58	    public List<ExperimentDto> getActiveExperiments() {
59	        return experimentRepository.findByActiveTrue().stream()
60	                .map(this::toDto).toList();
61	    }
62	
63	    /**
64	     * Deterministically assigns a user to a variant for a given experiment.
65	     * Uses SHA-256(userId + experimentName) mod variantCount.
66	     */
67	    @Transactional(readOnly = true)
68	    public Map<String, Object> getBucket(Long userId, String experimentName) {
69	        Experiment exp = experimentRepository.findByName(experimentName)
70	                .orElseThrow(() -> new IllegalArgumentException("Experiment not found: " + experimentName));
71	
72	        if (!exp.isActive()) {
73	            return Map.of("experiment", experimentName, "active", false, "variant", -1);
74	        }
75	
76	        int variant;
77	        if (exp.getType() == ExperimentType.BANDIT) {
78	            variant = banditBucket(exp, userId);
79	        } else {
80	            variant = deterministicBucket(userId, experimentName, exp.getVariantCount());
81	        }
82	
83	        return Map.of(
84	                "experiment", experimentName,
85	                "type", exp.getType().name(),
86	                "variant", variant,
87	                "variantCount", exp.getVariantCount(),
88	                "active", true
89	        );
90	    }
