114	    @Transactional
115	    public ExperimentDto rollback(Long experimentId) {
116	        Experiment exp = experimentRepository.findById(experimentId)
117	                .orElseThrow(() -> new IllegalArgumentException("Experiment not found"));
118	        // Rollback: reactivate and increment version to indicate reversion
119	        exp.setActive(true);
120	        exp.setVersion(exp.getVersion() + 1);
121	        return toDto(experimentRepository.save(exp));
122	    }
123	
124	    /**
125	     * Deterministic bucketing: SHA-256(userId + ":" + experimentName) mod variantCount.
126	     * Consistent for the same user+experiment pair, evenly distributed.
127	     */
128	    private int deterministicBucket(Long userId, String experimentName, int variantCount) {
129	        try {
130	            String input = userId + ":" + experimentName;
131	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
132	            byte[] hash = digest.digest(input.getBytes(StandardCharsets.UTF_8));
133	
134	            // Use first 4 bytes as unsigned int
135	            int value = ((hash[0] & 0xFF) << 24) | ((hash[1] & 0xFF) << 16)
136	                    | ((hash[2] & 0xFF) << 8) | (hash[3] & 0xFF);
137	
138	            return Math.abs(value) % variantCount;
139	        } catch (NoSuchAlgorithmException e) {
140	            throw new RuntimeException("SHA-256 not available", e);
141	        }
142	    }
143	
144	    /**
145	     * Deterministic epsilon-greedy bandit allocation.
146	     * Uses user+experiment hash to determine explore vs exploit deterministically per user.
147	     * Same user+experiment+version always gets the same assignment.
148	     */
149	    private int banditBucket(Experiment exp, Long userId) {
150	        // Deterministic exploration decision based on user hash
151	        int userHash = deterministicBucket(userId, exp.getName() + ":bandit", 100);
152	        boolean explore = userHash < (int)(EPSILON * 100); // e.g., 10% of users explore
153	
154	        if (explore) {
155	            // Deterministic random variant for exploration
156	            return deterministicBucket(userId, exp.getName() + ":explore:v" + exp.getVersion(), exp.getVariantCount());
157	        }
158	
159	        // Exploit: pick highest average reward variant
160	        List<Object[]> stats = outcomeRepository.getVariantStats(exp.getId());
161	        if (stats.isEmpty()) {
162	            return deterministicBucket(userId, exp.getName() + ":fallback", exp.getVariantCount());
163	        }
164	
165	        int bestVariant = -1;
166	        double bestAvg = Double.NEGATIVE_INFINITY;
167	        for (Object[] row : stats) {
168	            int v = ((Number) row[0]).intValue();
169	            long count = ((Number) row[1]).longValue();
170	            double totalReward = ((Number) row[2]).doubleValue();
171	            double avg = totalReward / count;
172	            if (avg > bestAvg) {
173	                bestAvg = avg;
174	                bestVariant = v;
175	            }
176	        }
177	        return bestVariant >= 0 ? bestVariant : deterministicBucket(userId, exp.getName(), exp.getVariantCount());
178	    }
179	
180	    @Audited(action = "RECORD_OUTCOME", entityType = "ExperimentOutcome")
181	    @Transactional
182	    public void recordOutcome(String experimentName, Long userId, int variant, double reward) {
183	        Experiment exp = experimentRepository.findByName(experimentName)
184	                .orElseThrow(() -> new IllegalArgumentException("Experiment not found"));
185	        User user = userId != null ? userRepository.findById(userId).orElse(null) : null;
186	        ExperimentOutcome outcome = ExperimentOutcome.builder()
187	                .experiment(exp).variant(variant).reward(reward).user(user).build();
188	        outcomeRepository.save(outcome);
189	    }
190	
191	    private ExperimentDto toDto(Experiment exp) {
192	        ExperimentDto dto = new ExperimentDto();
193	        dto.setId(exp.getId());
194	        dto.setName(exp.getName());
195	        dto.setType(exp.getType());
196	        dto.setVariantCount(exp.getVariantCount());
197	        dto.setDescription(exp.getDescription());
198	        dto.setActive(exp.isActive());
199	        dto.setVersion(exp.getVersion());
200	        return dto;
201	    }
202	}
