91	    @EnableMethodSecurity
92	    static class TestSecurityConfig {
93	        @Bean
94	        SecurityFilterChain testFilterChain(HttpSecurity http) throws Exception {
95	            http
96	                .csrf(AbstractHttpConfigurer::disable)
97	                .sessionManagement(s -> s.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
98	                .authorizeHttpRequests(auth -> auth
99	                    .requestMatchers("/api/auth/**").permitAll()
100	                    .requestMatchers("/api/admin/**").hasRole("ENTERPRISE_ADMIN")
101	                    .requestMatchers("/api/audit/**").hasAnyRole("ENTERPRISE_ADMIN", "SITE_MANAGER")
102	                    .requestMatchers("/api/credit-score/{userId}").hasAnyRole("ENTERPRISE_ADMIN", "SITE_MANAGER")
103	                    .anyRequest().authenticated()
104	                );
105	            return http.build();
106	        }
107	    }
